ALTER TABLE public.products
  ADD COLUMN IF NOT EXISTS seo_title text,
  ADD COLUMN IF NOT EXISTS seo_description text;

INSERT INTO public.landing_pages (slug, meta_title, meta_description, is_published, page_blocks)
VALUES
  ('webagentur-linz', 'Webagentur Linz | Webdesign, SEO & Websites', 'Webagentur in Linz für moderne Websites, klare Nutzerführung und saubere SEO-Basis. Digital-Perfect baut Seiten mit Struktur und Anfragefokus.', true, '[{"id": "hero-webagentur-linz", "type": "hero", "data": {"badge_text": "Webagentur Linz mit Fokus auf Anfragen, Sichtbarkeit und saubere Systeme", "headline": "Webagentur Linz\nfür Websites mit Struktur und Wirkung", "subheadline": "Digital-Perfect baut in Linz moderne Websites, Landingpages und SEO-Grundlagen für Unternehmen, die nicht irgendeine schöne Seite wollen, sondern ein System, das Vertrauen aufbaut und messbar neue Anfragen bringt.", "primary_cta_text": "Kostenloses Erstgespräch sichern", "primary_cta_href": "/#kontakt", "secondary_cta_text": "Leistungen ansehen", "secondary_cta_href": "/", "stats": [{"label": "Standort", "value": "Linz"}, {"label": "Fokus", "value": "Webdesign & SEO"}, {"label": "Ziel", "value": "Mehr Anfragen"}], "proof_items": [{"icon": "badge", "text": "Saubere Struktur statt Agentur-Chaos"}, {"icon": "chart", "text": "Conversion, Sichtbarkeit und Technik im selben System"}, {"icon": "shield", "text": "Direkt umsetzbar, wartbar und launch-ready"}], "visual_kicker": "Digitale Systeme", "visual_title": "Saubere Websites, SEO und klare Conversion-Strukturen statt Agentur-BlaBla.", "visual_badge": "Digital-Perfect", "layer_kicker": "Launch-ready", "layer_title": "Wir verbinden Premium-Design, technische Sauberkeit und messbare Sichtbarkeit.", "show_bottom_box1": true, "bottom_box1_kicker": "Fokus", "bottom_box1_title": "Webdesign, SEO & saubere Nutzerführung", "show_bottom_box2": true, "bottom_box2_kicker": "Ziel", "bottom_box2_title": "Mehr qualifizierte Anfragen statt mehr Oberflächenklicks"}}, {"id": "intro-webagentur-linz", "type": "rich_text", "data": {"kicker": "Warum Linz", "headline": "Webagentur in Linz heißt heute mehr als nur eine Website bauen", "body_html": "<p>Viele Unternehmen in Linz haben bereits eine Website, aber sie wirkt nicht wie ein Verkaufsinstrument. Oft fehlt eine klare Positionierung, die Startseite ist überladen, mobile Nutzer verlieren schnell die Orientierung und Suchmaschinen finden zu wenig verwertbaren Kontext. Genau an diesem Punkt setzt Digital-Perfect an. Wir bauen keine Deko-Seiten, sondern digitale Vertriebsflächen mit sauberer Informationsarchitektur, überzeugenden Einstiegen und einer klaren Nutzerführung.</p>\n<p>Für lokale Dienstleister, Agenturen, Beratungen, Handwerksbetriebe und kleine bis mittlere Unternehmen in Linz bedeutet das konkret: Die Seite muss schnell laden, auf dem Handy sofort verständlich sein, Vertrauen transportieren und den nächsten sinnvollen Schritt anbieten. Deshalb achten wir nicht nur auf Design, sondern auf Texte, Struktur, interne Verlinkung, technische Sauberkeit, Suchintention und Conversion-Logik.</p>\n<p>Eine starke Webagentur in Linz erkennt man nicht daran, dass sie viele Buzzwords benutzt. Man erkennt sie daran, dass Startseiten funktionieren, Unterseiten sauber differenziert sind, Meta-Daten stimmen, Inhalte eine klare Aufgabe haben und das System später im Alltag nicht auseinanderfällt. Genau dafür ist unser Setup ausgelegt.</p>"}}, {"id": "leistungen-webagentur-linz", "type": "rich_text", "data": {"kicker": "Leistung", "headline": "Was wir für Unternehmen in Linz konkret umsetzen", "body_html": "<p>Unsere Arbeit beginnt mit der Frage, welches Ergebnis die Website erzeugen soll. Geht es um mehr Anfragen, bessere lokale Sichtbarkeit, ein klareres Markenbild, mehr Vertrauen vor dem Erstkontakt oder darum, bisher verstreute Inhalte sauber zusammenzuführen? Auf dieser Basis bauen wir das passende Grundgerüst.</p>\n<h3>Typische Leistungen für Linz</h3>\n<ul>\n  <li>Konzeption von Startseiten und Leistungsseiten mit klarer Conversion-Struktur</li>\n  <li>Webdesign für lokale Unternehmen mit starker mobiler Nutzerführung</li>\n  <li>SEO-Basis für Linz inklusive sauberer Titel, Beschreibungen und interner Verlinkung</li>\n  <li>Landingpages für einzelne Leistungen oder Städte ohne dünnen Copy-Paste-Content</li>\n  <li>Optimierung von Ladezeiten, Bildern, Content-Blöcken und Seitentiefe</li>\n  <li>Aufbau einer klaren Seitenhierarchie für spätere Skalierung</li>\n</ul>\n<p>Wichtig ist: Nicht jede Firma in Linz braucht sofort zehn Unterseiten, einen Blog und fünf Tools. Viele brauchen zuerst eine fokussierte, vertrauenswürdige Seite mit wenigen, aber starken Wegen zum Kontakt. Genau dort holen wir euch ab. Danach kann das System Schritt für Schritt erweitert werden, ohne dass die Basis neu gebaut werden muss.</p>\n<p>Gerade in wettbewerbsstarken Bereichen ist das entscheidend. Wer heute lokal sichtbar werden will, braucht keine aufgeblasene Agentur-Show, sondern ein präzises Fundament, das fachlich sauber ist und im Alltag Bestand hat.</p>"}}, {"id": "trust-webagentur-linz", "type": "trust", "data": {"kicker": "Vorteile", "title": "Warum Unternehmen aus Linz mit Digital-Perfect arbeiten", "description": "Wir verbinden Design, Technik und SEO so, dass keine Seite hübsch aussieht, aber operativ schwach bleibt.", "items": [{"title": "Mobile-first gedacht", "desc": "Texte, Einstiege und CTAs werden zuerst für echte mobile Nutzung geplant, nicht nachträglich zusammengeschoben.", "icon": "gauge"}, {"title": "SEO ohne Content-Müll", "desc": "Wir bauen Seiten mit klarer Suchintention und genug Substanz, statt dünne Keyword-Flächen zu produzieren.", "icon": "chart"}, {"title": "Saubere technische Basis", "desc": "Struktur, Routing, Metadaten und Performance werden so umgesetzt, dass spätere Skalierung nicht zum Sanierungsfall wird.", "icon": "shield"}, {"title": "Direkte Umsetzbarkeit", "desc": "Kein Konzernprozess. Klare Entscheidungen, schnelle Umsetzung und ein Setup, das im echten Tagesgeschäft funktioniert.", "icon": "users"}]}}, {"id": "prozess-webagentur-linz", "type": "rich_text", "data": {"kicker": "Ablauf", "headline": "So läuft ein typisches Projekt mit einer Webagentur aus Linz ab", "body_html": "<p>Der Ablauf ist bewusst schlank gehalten. Wir starten mit Ziel, Zielgruppe, Angebotslogik und bestehendem Material. Danach definieren wir die Seitenstruktur, priorisieren Startseite und Leistungsseiten und klären, welche Inhalte wirklich benötigt werden. Das spart Zeit, verhindert Leerlauf und sorgt dafür, dass keine Seite mit Füllmaterial online geht.</p>\n<p>Im nächsten Schritt entsteht das Design- und Content-Gerüst. Dabei achten wir auf klare H1-/H2-Struktur, sinnvolle Abschnitte, interne Links und sichtbare Kontaktpunkte. Danach folgt die technische Umsetzung inklusive Performance, SEO-Basis und Feinschliff für Mobilgeräte. Erst wenn alles sauber sitzt, geht die Seite live.</p>\n<p>Für Unternehmen aus Linz ist das besonders wertvoll, weil der regionale Wettbewerb oft nicht über reine Design-Optik entschieden wird, sondern über Klarheit, Vertrauen und Zugänglichkeit. Genau deshalb bauen wir Systeme, die im Alltag wirken und nicht nur in der Präsentation gut aussehen.</p>\n<p><a href=\"/#kontakt\">Jetzt Kontakt aufnehmen</a> oder direkt weitere Leistungen auf der <a href=\"/\">Startseite</a> ansehen.</p>"}}, {"id": "faq-webagentur-linz", "type": "faq", "data": {"kicker": "FAQ", "title": "Häufige Fragen zu Webagentur Linz", "description": "Die wichtigsten Fragen zu Webdesign, SEO und Zusammenarbeit auf einen Blick.", "items": [{"question": "Für wen eignet sich eure Webagentur in Linz?", "answer": "Vor allem für lokale Dienstleister, KMU, Agenturen und Unternehmen, die eine klare, moderne Website mit Fokus auf Sichtbarkeit und Anfragen brauchen."}, {"question": "Macht ihr nur Design oder auch SEO?", "answer": "Wir denken Design, Struktur, technische Basis und SEO immer zusammen. Genau das verhindert später doppelte Arbeit und schwache Unterseiten."}, {"question": "Kann man bestehende Inhalte weiterverwenden?", "answer": "Ja, aber nur dort, wo sie strategisch Sinn ergeben. Dünne oder veraltete Inhalte werden sauber neu strukturiert oder ersetzt."}, {"question": "Ist auch Betreuung nach dem Launch möglich?", "answer": "Ja. Inhalte, Landingpages, Produktseiten und technische Optimierungen können nach dem Launch weiter ausgebaut werden."}]}}]'::jsonb),
  ('webdesign-graz-dein-webdesigner-aus-linz', 'Webdesign Graz | Webdesigner & SEO aus Linz', 'Webdesign für Graz mit klarer Struktur, mobiler Nutzerführung und sauberer SEO-Basis. Digital-Perfect entwickelt starke Stadtseiten statt Textkopien.', true, '[{"id": "hero-webdesign-graz", "type": "hero", "data": {"badge_text": "Webdesign Graz mit klarer Linie, sauberer Technik und echtem Nutzwert", "headline": "Webdesign Graz\nmit Struktur statt Showeffekt", "subheadline": "Auch wenn wir in Linz sitzen, bauen wir für Unternehmen in Graz Websites, die modern aussehen, lokal verständlich positioniert sind und technisch so sauber umgesetzt werden, dass daraus echte Sichtbarkeit und qualifizierte Anfragen entstehen können.", "primary_cta_text": "Projekt anfragen", "primary_cta_href": "/#kontakt", "secondary_cta_text": "Unsere Leistungen", "secondary_cta_href": "/", "stats": [{"label": "Region", "value": "Graz"}, {"label": "Fokus", "value": "Webdesign"}, {"label": "Plus", "value": "SEO-Basis"}], "proof_items": [{"icon": "badge", "text": "Klares Design mit funktionalem Seitenaufbau"}, {"icon": "chart", "text": "Struktur für lokale Auffindbarkeit und bessere Orientierung"}, {"icon": "shield", "text": "Technisch sauber statt schnell zusammengeklickt"}], "visual_kicker": "Digitale Systeme", "visual_title": "Saubere Websites, SEO und klare Conversion-Strukturen statt Agentur-BlaBla.", "visual_badge": "Digital-Perfect", "layer_kicker": "Launch-ready", "layer_title": "Wir verbinden Premium-Design, technische Sauberkeit und messbare Sichtbarkeit.", "show_bottom_box1": true, "bottom_box1_kicker": "Fokus", "bottom_box1_title": "Webdesign, SEO & saubere Nutzerführung", "show_bottom_box2": true, "bottom_box2_kicker": "Ziel", "bottom_box2_title": "Mehr qualifizierte Anfragen statt mehr Oberflächenklicks"}}, {"id": "intro-webdesign-graz", "type": "rich_text", "data": {"kicker": "Positionierung", "headline": "Webdesign für Graz muss zuerst verständlich sein – dann schön", "body_html": "<p>Viele Websites im Raum Graz scheitern nicht daran, dass sie hässlich sind. Sie scheitern daran, dass sie unklar sind. Besucher verstehen zu spät, wofür das Unternehmen steht, welche Leistung genau angeboten wird und warum gerade diese Lösung Vertrauen verdient. Genau deshalb setzen wir beim Webdesign für Graz zuerst auf Verständlichkeit, klare Gliederung und logische Seitenarchitektur.</p>\n<p>Ein gutes Webdesign ist nicht bloß ein modernes Layout. Es ist die sichtbare Form einer sauberen Entscheidungskette: Wer ist die Zielgruppe, welche Fragen stellt sie sich zuerst, welche Informationen braucht sie vor dem Erstkontakt und wie führen wir sie mit so wenig Reibung wie möglich zur passenden Aktion? Wenn diese Basis stimmt, kann das visuelle Design seine volle Wirkung entfalten.</p>\n<p>Für Unternehmen in Graz bedeutet das: bessere Lesbarkeit, fokussierte Botschaften, weniger Ablenkung, mehr Vertrauen und ein professionellerer Eindruck über alle Geräte hinweg. Genau das ist am Ende die Voraussetzung dafür, dass aus Klicks Anfragen werden.</p>"}}, {"id": "konzept-webdesign-graz", "type": "rich_text", "data": {"kicker": "Konzept", "headline": "Was wir bei Webdesign-Projekten für Graz besonders sauber lösen", "body_html": "<p>Wir planen Startseiten, Leistungsseiten und Kontaktwege so, dass Nutzer nicht suchen müssen. Dazu gehören klare Einstiegsbereiche, belastbare Nutzenargumente, inhaltlich starke Zwischenabschnitte, passende lokale Begriffe und ein sauberer Abschluss mit Kontaktoption. Außerdem achten wir darauf, dass jede wichtige Unterseite eine eigene Aufgabe bekommt und nicht nur eine Wiederholung der Startseite ist.</p>\n<h3>Worauf wir im Alltag achten</h3>\n<ul>\n  <li>eine verständliche H1-Struktur ohne Mehrfach-Signale</li>\n  <li>einzigartige Meta-Daten pro URL statt duplizierter Standards</li>\n  <li>genug Texttiefe, damit Seiten nicht in dünnem Boilerplate-Content enden</li>\n  <li>starke mobile Lesbarkeit und klare Scroll-Logik</li>\n  <li>interne Links, die Nutzer wirklich weiterführen</li>\n</ul>\n<p>Gerade bei Stadtseiten wird häufig geschlampt: gleiche Texte, nur der Ortsname geändert. Das ist schwach für Nutzer und Suchmaschinen. Deshalb schreiben wir auch für Graz Inhalte mit eigener Argumentation, eigener Struktur und eigenem Mehrwert.</p>"}}, {"id": "trust-webdesign-graz", "type": "trust", "data": {"kicker": "Mehrwert", "title": "Warum Unternehmen in Graz von sauberem Webdesign profitieren", "description": "Starke Stadtseiten funktionieren nur dann, wenn Inhalt, Design und Technik dieselbe Sprache sprechen.", "items": [{"title": "Klarer Erstkontakt", "desc": "Besucher verstehen schneller, was ihr anbietet und welcher nächste Schritt sinnvoll ist.", "icon": "users"}, {"title": "Mehr lokale Relevanz", "desc": "Die Seite ist nicht generisch, sondern spricht Anforderungen und Suchmuster für Graz nachvollziehbar an.", "icon": "chart"}, {"title": "Weniger Reibung", "desc": "Navigation, Abschnittsaufbau und Inhalte werden so geplant, dass Nutzer nicht abspringen, weil sie den roten Faden verlieren.", "icon": "gauge"}, {"title": "Skalierbare Basis", "desc": "Die Struktur ist so gebaut, dass später weitere Leistungen, Städte oder SEO-Seiten sauber ergänzt werden können.", "icon": "shield"}]}}, {"id": "abschluss-webdesign-graz", "type": "rich_text", "data": {"kicker": "Zusammenarbeit", "headline": "Webdesign Graz aus Linz – remote, direkt und ohne unnötige Schleifen", "body_html": "<p>Die Zusammenarbeit funktioniert unkompliziert. Ziele, Inhalte und Struktur lassen sich heute effizient abstimmen, ohne dass ein Projekt künstlich aufgeblasen wird. Wichtig ist nicht, wo jemand sitzt, sondern ob das Ergebnis fachlich sitzt. Genau darauf ist unser Prozess ausgerichtet.</p>\n<p>Wenn ihr für Graz eine Website wollt, die modern wirkt, sauber performt und später nicht wegen Technik, Metadaten oder Inhaltsarmut nachgebessert werden muss, ist jetzt der richtige Zeitpunkt für ein sauberes Fundament. Denn ein gutes System spart später nicht nur Geld, sondern auch verlorene Sichtbarkeit.</p>\n<p>Mehr über unsere Arbeitsweise erfahrt ihr auf der <a href=\"/webagentur-linz\">Seite zur Webagentur Linz</a> oder direkt über <a href=\"/#kontakt\">unser Kontaktformular</a>.</p>"}}, {"id": "faq-webdesign-graz", "type": "faq", "data": {"kicker": "FAQ", "title": "Häufige Fragen zu Webdesign Graz", "description": "Kurz, konkret und ohne Agenturfloskeln.", "items": [{"question": "Arbeitet ihr auch für Kunden in Graz, obwohl ihr in Linz sitzt?", "answer": "Ja. Konzept, Design, Inhalte und Abstimmungen lassen sich effizient remote umsetzen. Entscheidend ist die Qualität der Umsetzung, nicht die Distanz."}, {"question": "Ist auf der Seite auch lokale SEO für Graz möglich?", "answer": "Ja. Jede Stadtseite bekommt eigene Meta-Daten, eigene Inhalte und eine saubere interne Verlinkung statt bloßer Ortsnamen-Kopien."}, {"question": "Kann bestehendes Material eingebunden werden?", "answer": "Ja, sofern es fachlich sauber ist. Veraltete oder zu dünne Inhalte werden von uns überarbeitet oder neu aufgebaut."}, {"question": "Wie viel Text braucht eine starke Stadtseite?", "answer": "Genug, um Suchintention, Vertrauen und Leistung nachvollziehbar abzudecken. Dünne 200-Wörter-Seiten reichen in der Regel nicht."}]}}]'::jsonb),
  ('webagentur-wien-webdesign-wien', 'Webagentur Wien | Webdesign & SEO Lösungen', 'Webagentur Wien für starke Websites, saubere Redirects, klare Inhalte und lokale SEO-Struktur. Digital-Perfect baut belastbare Relaunch-Basen.', true, '[{"id": "hero-webagentur-wien", "type": "hero", "data": {"badge_text": "Webagentur Wien für klare Positionierung, starke Landingpages und sauberes SEO", "headline": "Webagentur Wien\nfür starke Auftritte ohne leere Hülle", "subheadline": "Unternehmen in Wien brauchen keinen generischen Agentur-Look, sondern Websites mit klarer Struktur, glaubwürdigen Inhalten und einer technischen Basis, die Sichtbarkeit, Vertrauen und Conversion zusammenbringt. Genau dafür bauen wir Digital-Perfect.", "primary_cta_text": "Kostenloses Gespräch starten", "primary_cta_href": "/#kontakt", "secondary_cta_text": "Mehr Leistungen ansehen", "secondary_cta_href": "/", "stats": [{"label": "Markt", "value": "Wien"}, {"label": "Setup", "value": "Webdesign + SEO"}, {"label": "Ansatz", "value": "Strategisch"}], "proof_items": [{"icon": "badge", "text": "Starke Einstiege statt austauschbarer Agenturtexte"}, {"icon": "chart", "text": "Unterseiten mit echter Such- und Nutzerlogik"}, {"icon": "shield", "text": "Saubere Technik für Launch und Skalierung"}], "visual_kicker": "Digitale Systeme", "visual_title": "Saubere Websites, SEO und klare Conversion-Strukturen statt Agentur-BlaBla.", "visual_badge": "Digital-Perfect", "layer_kicker": "Launch-ready", "layer_title": "Wir verbinden Premium-Design, technische Sauberkeit und messbare Sichtbarkeit.", "show_bottom_box1": true, "bottom_box1_kicker": "Fokus", "bottom_box1_title": "Webdesign, SEO & saubere Nutzerführung", "show_bottom_box2": true, "bottom_box2_kicker": "Ziel", "bottom_box2_title": "Mehr qualifizierte Anfragen statt mehr Oberflächenklicks"}}, {"id": "einordnung-webagentur-wien", "type": "rich_text", "data": {"kicker": "Einordnung", "headline": "Wer in Wien sichtbar sein will, braucht mehr als nur ein schickes Frontend", "body_html": "<p>Wien ist groß, wettbewerbsstark und in vielen Branchen inhaltlich überfüllt. Genau deshalb reicht es nicht, eine visuell gute Website online zu stellen und zu hoffen, dass daraus automatisch Sichtbarkeit oder Anfragen entstehen. Eine starke Webagentur für Wien muss die Seite als System denken: Welche Leistung steht im Mittelpunkt, welche Nutzergruppen kommen zuerst, welche Fragen müssen beantwortet werden und wie übersetzen wir das alles in eine überzeugende Struktur?</p>\n<p>Das Ziel ist nicht, möglichst viel auf eine Seite zu packen. Das Ziel ist, die richtigen Signale sauber zu setzen. Dazu gehören eine starke H1, eindeutige Seitentitel, unterschiedliche Metabeschreibungen, klare Abschnittslogik, genug Texttiefe und ein sinnvoller Mix aus Vertrauen, Leistung und Handlung. Wenn diese Punkte stimmen, arbeitet die Website nicht mehr gegen euch, sondern für euch.</p>\n<p>Besonders in Wien ist das entscheidend, weil Nutzer sehr schnell vergleichen. Wer unklar wirkt, verliert. Wer klar, professionell und strukturiert auftritt, gewinnt häufig schon vor dem ersten Kontakt.</p>"}}, {"id": "leistungen-webagentur-wien", "type": "rich_text", "data": {"kicker": "Leistungen", "headline": "Unsere typischen Schwerpunkte für Webagentur- und Webdesign-Projekte in Wien", "body_html": "<p>Wir unterstützen Unternehmen in Wien dabei, aus ihrer Website ein belastbares Akquise- und Vertrauenssystem zu machen. Je nach Ausgangslage kann das bedeuten, eine bestehende Seite zu entschlacken, die Navigation neu zu ordnen, Landingpages gezielter aufzubauen oder die technische Basis samt SEO-Signalen sauber nachzuziehen.</p>\n<ul>\n  <li>Startseiten mit klarer Positionierung und sauberem Angebotseinstieg</li>\n  <li>Leistungsseiten mit differenzierten Nutzenargumenten statt Floskel-Texten</li>\n  <li>lokale SEO-Strukturen mit einzigartigen Meta-Daten und sinnvoller interner Verlinkung</li>\n  <li>Produkt- und Landingpages mit genug Texttiefe für Nutzer und Suchmaschinen</li>\n  <li>Technische Qualität bei Routing, Canonicals und Weiterleitungen</li>\n</ul>\n<p>Gerade wenn eine Website aus mehreren alten Systemen, inkonsistenten URLs oder doppelten Inhalten entstanden ist, braucht es einen klaren Cleanup. Das spart Sichtbarkeitsverluste und schafft eine belastbare Grundlage für neue Inhalte, Kampagnen und Erweiterungen.</p>"}}, {"id": "trust-webagentur-wien", "type": "trust", "data": {"kicker": "Warum wir", "title": "Darum ist unser Setup für Wien besonders stark", "description": "Wir kombinieren strategische Klarheit mit technischer Exekution, damit starke Ideen nicht an schwacher Umsetzung scheitern.", "items": [{"title": "Einzigartige Zielseiten", "desc": "Jede relevante URL bekommt eigene Metadaten, klare Inhalte und eine definierte Aufgabe im Funnel.", "icon": "chart"}, {"title": "Saubere Weiterleitungen", "desc": "Legacy-Pfade werden nicht einfach vergessen, sondern per 301 auf die passenden neuen Ziele gezogen.", "icon": "shield"}, {"title": "Mehr Vertrauen im Erstkontakt", "desc": "Starke Gliederung, sauberer Text und klare CTAs helfen, schneller professionell wahrgenommen zu werden.", "icon": "users"}, {"title": "Technik ohne Ballast", "desc": "Wir halten das Setup schlank, wartbar und so robust, dass spätere Erweiterungen nicht alles blockieren.", "icon": "gauge"}]}}, {"id": "abschluss-webagentur-wien", "type": "rich_text", "data": {"kicker": "Launch-ready", "headline": "Webagentur Wien mit sauberem Fundament statt späterem Reparaturmodus", "body_html": "<p>Die beste Zeit für einen sauberen Relaunch ist vor dem Launch, nicht danach. Wenn alte Pfade brechen, Metadaten dupliziert sind oder neue Seiten zu wenig Substanz mitbringen, kostet das Sichtbarkeit und Vertrauen. Deshalb setzen wir Relaunches so auf, dass Inhalt, Routing, Redirects und SEO-Signale von Anfang an zusammenpassen.</p>\n<p>Für Unternehmen in Wien bedeutet das weniger Risiko, mehr Klarheit und bessere Voraussetzungen, um mit neuen Seiten wirklich zu ranken statt nur online zu sein. Wer heute sauber aufsetzt, spart sich später teure Nacharbeiten.</p>\n<p>Wenn ihr direkt eine fokussierte Hauptseite sehen wollt, schaut auf <a href=\"/webagentur-linz\">Webagentur Linz</a>. Für Kontakt oder Projektstart geht es hier entlang: <a href=\"/#kontakt\">Kontakt aufnehmen</a>.</p>"}}, {"id": "faq-webagentur-wien", "type": "faq", "data": {"kicker": "FAQ", "title": "Häufige Fragen zu Webagentur Wien & Webdesign Wien", "description": "Die typischen Fragen vor einem Relaunch oder Stadtseiten-Ausbau.", "items": [{"question": "Warum braucht Wien eine eigene Seite und nicht nur eine allgemeine Leistungsseite?", "answer": "Weil Suchintention, Wettbewerb und Nutzererwartung lokal variieren. Eine eigene Seite schafft mehr Relevanz und mehr Klarheit."}, {"question": "Könnt ihr auch alte URLs aus einem früheren System auffangen?", "answer": "Ja. Genau dafür setzen wir saubere 301-Weiterleitungen auf, damit bestehende Signale nicht ins Leere laufen."}, {"question": "Was ist bei Webdesign Wien der häufigste Fehler?", "answer": "Austauschbare Inhalte, fehlende Differenzierung und zu wenig strategische Tiefe. Optisch modern allein reicht nicht."}, {"question": "Eignet sich die Seite auch als Basis für weitere Städte oder Leistungen?", "answer": "Ja. Die Struktur wird so aufgebaut, dass neue Zielseiten später sauber ergänzt werden können."}]}}]'::jsonb)
ON CONFLICT (slug) DO UPDATE
SET
  meta_title = EXCLUDED.meta_title,
  meta_description = EXCLUDED.meta_description,
  is_published = EXCLUDED.is_published,
  page_blocks = EXCLUDED.page_blocks;

DO $$
DECLARE
  v_has_site_id boolean;
  v_product_id uuid;
  v_default_site_id uuid := '00000000-0000-0000-0000-000000000001';
BEGIN
  SELECT EXISTS (
    SELECT 1
    FROM information_schema.columns
    WHERE table_schema = 'public'
      AND table_name = 'products'
      AND column_name = 'site_id'
  ) INTO v_has_site_id;

  SELECT id
  INTO v_product_id
  FROM public.products
  WHERE lower(slug) = 'google-bewertungsstander-nfc-qr-code'
